// State
let currentPage = 'home';
let scrollProgress = 0;
let targetScroll = 0;
const defaultBg = 'https://images.unsplash.com/photo-1499209974431-9dddcece7f88?w=1600&q=80';
let animationFrame;

// Elements
const hamburger = document.getElementById('hamburger');
const menuOverlay = document.getElementById('menuOverlay');
const heroPage = document.getElementById('heroPage');
const heroBg = document.getElementById('heroBg');
const healingPage = document.getElementById('healingPage');
const gongPage = document.getElementById('gongPage');
const aboutPage = document.getElementById('aboutPage');

// Set default background
heroBg.style.backgroundImage = `url(${defaultBg})`;

// Smooth lerp function for momentum scrolling
function lerp(start, end, factor) {
    return start + (end - start) * factor;
}

// Animation loop for smooth scrolling with momentum
function animate() {
    const newValue = lerp(scrollProgress, targetScroll, 0.1);
    
    if (Math.abs(newValue - targetScroll) < 0.01) {
        scrollProgress = targetScroll;
        
        if (targetScroll >= 100) {
            setTimeout(() => {
                currentPage = 'home';
                scrollProgress = 0;
                targetScroll = 0;
                heroBg.style.backgroundImage = `url(${defaultBg})`;
                hideAllSections();
                heroPage.classList.remove('hidden');
                hamburger.classList.remove('dark');
            }, 100);
        }
    } else {
        scrollProgress = newValue;
        updateSectionPosition();
        animationFrame = requestAnimationFrame(animate);
    }
}

// Update section position based on scroll progress
function updateSectionPosition() {
    const activePage = document.querySelector('.section-page:not(.hidden)');
    if (activePage && currentPage !== 'home') {
        activePage.style.transform = `translateY(-${scrollProgress}vh)`;
    }
}

// Wheel event with momentum scrolling
window.addEventListener('wheel', (e) => {
    if (currentPage !== 'home') {
        e.preventDefault();
        
        if (e.deltaY > 0) {
            targetScroll = Math.min(targetScroll + 8, 100);
        } else {
            targetScroll = Math.max(targetScroll - 8, 0);
        }
        
        if (!animationFrame) {
            animationFrame = requestAnimationFrame(animate);
        }
    }
}, { passive: false });

// Hide all section pages
function hideAllSections() {
    healingPage.classList.add('hidden');
    gongPage.classList.add('hidden');
    aboutPage.classList.add('hidden');
}

// Navigate to a specific page
function navigateToPage(page) {
    currentPage = page;
    scrollProgress = 0;
    targetScroll = 0;
    hideAllSections();
    heroPage.classList.remove('hidden');
    
    if (page === 'healing') {
        healingPage.classList.remove('hidden');
        hamburger.classList.add('dark');
    } else if (page === 'gong') {
        gongPage.classList.remove('hidden');
        hamburger.classList.add('dark');
    } else if (page === 'about') {
        aboutPage.classList.remove('hidden');
        hamburger.classList.add('dark');
    } else {
        hamburger.classList.remove('dark');
    }
    
    heroBg.style.backgroundImage = `url(${defaultBg})`;
}

// Hamburger menu toggle
hamburger.addEventListener('click', () => {
    hamburger.classList.toggle('open');
    menuOverlay.classList.toggle('active');
});

// Menu links navigation
document.querySelectorAll('.menu-links a').forEach(link => {
    link.addEventListener('click', (e) => {
        e.preventDefault();
        const page = e.target.dataset.page;
        navigateToPage(page);
        hamburger.classList.remove('open');
        menuOverlay.classList.remove('active');
    });
});

// Hero links navigation and background hover
document.querySelectorAll('.hero-links a').forEach(link => {
    link.addEventListener('click', (e) => {
        e.preventDefault();
        const page = e.target.dataset.page;
        navigateToPage(page);
    });
    
    // Change background on hover
    link.addEventListener('mouseenter', (e) => {
        const image = e.target.dataset.image;
        if (image) {
            heroBg.style.backgroundImage = `url(${image})`;
        }
    });
    
    link.addEventListener('mouseleave', () => {
        heroBg.style.backgroundImage = `url(${defaultBg})`;
    });
});